namespace sv_8c23905eac1a40369adcc3020b97ac67.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@using sv_8c23905eac1a40369adcc3020b97ac67.Services

<div class="product-card" @onclick="HandleCardClick" style="border:1px solid #ddd;border-radius:8px;padding:16px;cursor:pointer;display:flex;flex-direction:column;gap:8px;">
    <div style="background:#e0e0e0;height:180px;display:flex;align-items:center;justify-content:center;border-radius:4px;">
        <span style="color:#888;">@Product.Name</span>
    </div>

    <h4 style="margin:0;">@Product.Name</h4>

    <span style="font-size:1.1rem;font-weight:bold;color:#2e7d32;">@Product.Price.ToString("C")</span>

    <span title="@($"{Product.Rating:F1} out of 5")">@RatingStars</span>

    @if (!Product.InStock)
    {
        <span style="background:#ef5350;color:white;padding:2px 8px;border-radius:4px;font-size:0.85rem;align-self:flex-start;">
            Out of Stock
        </span>
    }

    <button disabled="@(!Product.InStock)" @onclick="HandleAddToCart" @onclick:stopPropagation="true"
            style="margin-top:auto;padding:8px 12px;border:none;border-radius:4px;cursor:pointer;
                   background:@(Product.InStock ? "#1976d2" : "#bdbdbd");color:white;">
        Add to Cart
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private string RatingStars
    {
        get
        {
            int filled = (int)Math.Round(Product.Rating);
            return new string('★', filled) + new string('☆', 5 - filled);
        }
    }

    private async Task HandleCardClick() => await OnProductSelected.InvokeAsync(Product);

    private async Task HandleAddToCart() => await OnAddToCart.InvokeAsync(Product);
}

@using sv_8c23905eac1a40369adcc3020b97ac67.Services

<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(240px,1fr));gap:16px;">
    @foreach (var product in Products)
    {
        <ProductCard Product="product"
                     OnProductSelected="OnProductSelected"
                     OnAddToCart="OnAddToCart" />
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = [];

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@using sv_8c23905eac1a40369adcc3020b97ac67.Services

<div style="display:flex;flex-direction:column;gap:16px;">
    <h3 style="margin:0;">Filters</h3>

    <fieldset style="border:1px solid #ddd;border-radius:4px;padding:12px;">
        <legend>Category</legend>
        @foreach (var category in Categories)
        {
            <label style="display:block;margin-bottom:4px;">
                <input type="checkbox" checked="@IsSelected(category)" @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                @category
            </label>
        }
    </fieldset>

    <fieldset style="border:1px solid #ddd;border-radius:4px;padding:12px;">
        <legend>Price Range</legend>
        <label style="display:block;margin-bottom:4px;">
            Min
            <input type="number" min="0" step="0.01" value="@_minPrice"
                   @onchange="e => _minPrice = ParseDecimal(e.Value)" style="width:100%;box-sizing:border-box;" />
        </label>
        <label style="display:block;">
            Max
            <input type="number" min="0" step="0.01" value="@_maxPrice"
                   @onchange="e => _maxPrice = ParseDecimal(e.Value)" style="width:100%;box-sizing:border-box;" />
        </label>
    </fieldset>

    <label style="display:flex;align-items:center;gap:6px;">
        <input type="checkbox" @bind="_inStockOnly" />
        In Stock Only
    </label>

    <button @onclick="ApplyFilters"
            style="padding:10px;background:#1976d2;color:white;border:none;border-radius:4px;cursor:pointer;">
        Apply Filters
    </button>

    <button @onclick="ClearFilters"
            style="padding:10px;background:#757575;color:white;border:none;border-radius:4px;cursor:pointer;">
        Clear Filters
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public ProductFilter? CurrentFilter { get; set; }

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    private HashSet<string> _selectedCategories = [];
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    protected override void OnParametersSet()
    {
        if (CurrentFilter is not null)
        {
            _selectedCategories = CurrentFilter.Categories is not null
                ? new HashSet<string>(CurrentFilter.Categories)
                : [];
            _minPrice = CurrentFilter.MinPrice;
            _maxPrice = CurrentFilter.MaxPrice;
            _inStockOnly = CurrentFilter.InStockOnly;
        }
    }

    private bool IsSelected(string category) => _selectedCategories.Contains(category);

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked) _selectedCategories.Add(category);
        else _selectedCategories.Remove(category);
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString())) return null;
        return decimal.TryParse(value.ToString(), out var d) ? d : null;
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            _minPrice, _maxPrice, _inStockOnly);
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnFilterApplied.InvokeAsync(new ProductFilter(null, null, null, false));
    }
}

@page "/catalog"
@using sv_8c23905eac1a40369adcc3020b97ac67.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h2>Product Catalog</h2>

@if (_error is not null)
{
    <div style="padding:16px;background:#ffebee;color:#c62828;border-radius:4px;margin-bottom:16px;">
        <strong>Error:</strong> @_error
        <button @onclick="LoadDataAsync" style="margin-left:12px;padding:4px 12px;cursor:pointer;">Retry</button>
    </div>
}

<div style="display:flex;gap:24px;align-items:flex-start;">
    @* --- Left sidebar (25%) --- *@
    <aside style="flex:0 0 25%;min-width:200px;">
        <CatalogFilters Categories="_categories"
                        CurrentFilter="_filter"
                        OnFilterApplied="HandleFilterApplied" />
    </aside>

    @* --- Main content (75%) --- *@
    <main style="flex:1;">
        <CatalogToolbar SortBy="@_sortBy"
                        Page="_page"
                        PageSize="PageSize"
                        TotalCount="_totalCount"
                        OnSortChanged="HandleSortChanged" />

        @if (_loading)
        {
            <div style="text-align:center;padding:48px;color:#888;">Loading products…</div>
        }
        else if (_products.Count == 0)
        {
            <div style="text-align:center;padding:48px;color:#888;">
                No products match your criteria. Try adjusting your filters.
            </div>
        }
        else
        {
            <ProductGrid Products="_products"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />
        }

        @if (_totalPages > 1)
        {
            <CatalogPagination CurrentPage="_page"
                               TotalPages="_totalPages"
                               OnPageChanged="HandlePageChanged" />
        }
    </main>
</div>

@code {
    private const int PageSize = 12;

    private List<Product> _products = [];
    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _page = 1;
    private int _totalCount;
    private int _totalPages;
    private bool _loading = true;
    private string? _error;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            _error = null;
            _loading = true;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(_filter, _sortBy, _page, PageSize);
            await Task.WhenAll(categoriesTask, productsTask);

            _categories = categoriesTask.Result;
            ApplyResult(productsTask.Result);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            _error = null;
            _loading = true;
            var result = await ProductService.SearchAsync(_filter, _sortBy, _page, PageSize);
            ApplyResult(result);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void ApplyResult(PagedResult<Product> result)
    {
        _products = result.Items;
        _totalCount = result.TotalCount;
        _totalPages = (int)Math.Ceiling((double)result.TotalCount / PageSize);
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _page = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _page = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _page = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        await OnAddToCart.InvokeAsync(product);
    }
}

